// Generated by scratchpad/gen_bluenoise.py — 64x64 RGBA blue noise
// (void-and-cluster, toroidal, 4 independent channels). Used as low-discrepancy
// per-pixel random numbers for the first sampling dimensions: residual noise
// becomes high-frequency, which the denoiser and TAA remove far better than
// the blotchy low-frequency clumps of white noise.
const B64 =
  "";

/** 64*64*4 bytes, row-major RGBA, values 0..255 (treat as value/255 + 0.5/255). */
export function decodeBlueNoise() {
  const bin = atob(B64);
  const out = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) out[i] = bin.charCodeAt(i);
  return out;
}

export const BLUE_NOISE_SIZE = 64;
